final:
module Comparator16Bit (
    input [15:0] A,
    input [15:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);
  wire [15:0] _tap_A = A & {16{1'b1}};


always @(*) begin
    if (A > B) begin
        A_greater = 1'b1;
        A_equal = 1'b0;
        A_less = 1'b0;
    end else if (A == B) begin
        A_greater = 1'b0;
        A_equal = 1'b1;
        A_less = 1'b0;
    end else begin
        A_greater = 1'b0;
        A_equal = 1'b0;
        A_less = 1'b1;
    end
end

endmodule
